import{_ as a,o as e,c as r,ae as o}from"./chunks/framework.C2r4g--V.js";const g=JSON.parse('{"title":"两个 AI Agent、两个平台、一杯咖啡的成本 —— 我们的多 Agent 协作实践","description":"","frontmatter":{},"headers":[],"relativePath":"share/meetup-multiagent-practice.md","filePath":"share/meetup-multiagent-practice.md"}'),l={name:"share/meetup-multiagent-practice.md"};function n(d,t,i,h,p,s){return e(),r("div",null,[...t[0]||(t[0]=[o('<h1 id="两个-ai-agent、两个平台、一杯咖啡的成本-——-我们的多-agent-协作实践" tabindex="-1">两个 AI Agent、两个平台、一杯咖啡的成本 —— 我们的多 Agent 协作实践 <a class="header-anchor" href="#两个-ai-agent、两个平台、一杯咖啡的成本-——-我们的多-agent-协作实践" aria-label="Permalink to &quot;两个 AI Agent、两个平台、一杯咖啡的成本 —— 我们的多 Agent 协作实践&quot;">​</a></h1><blockquote><p>这是 2026 年 3 月 OpenClaw Meetup 北京站的分享整理，记录我们如何用极低成本跑起来一套生产级多 Agent 协作系统。</p></blockquote><hr><h2 id="先讲一个失败的故事" tabindex="-1">先讲一个失败的故事 <a class="header-anchor" href="#先讲一个失败的故事" aria-label="Permalink to &quot;先讲一个失败的故事&quot;">​</a></h2><p>6 小时。</p><p>这是我们系统宕机的时间。原因不是代码 bug，是一个 stale lock 文件把 gateway 卡死了。两个 Agent 同时离线，没有告警，没有自动恢复。我 SSH 进去手动重启，才发现问题。</p><p>今天我想分享的，就是从这次失败开始，我们怎么用一杯咖啡的成本跑起来一套多 Agent 协作系统。</p><hr><h2 id="双平台部署方案" tabindex="-1">双平台部署方案 <a class="header-anchor" href="#双平台部署方案" aria-label="Permalink to &quot;双平台部署方案&quot;">​</a></h2><p>我们跑了两个 OpenClaw Agent —— GSD 和 WLB：</p><table tabindex="0"><thead><tr><th></th><th>GSD (Railway)</th><th>WLB (ClawCloud Run)</th></tr></thead><tbody><tr><td>类型</td><td>托管容器</td><td>持久容器</td></tr><tr><td>冷启动</td><td>有（~30s）</td><td>无</td></tr><tr><td>资源</td><td>~512MB</td><td>16 cores + 123GB</td></tr><tr><td>月成本</td><td>$0-5</td><td>¥0（免费额度）</td></tr></tbody></table><p><strong>Railway</strong> 用的是社区模板 <code>clawdbot-railway-template</code>，5 分钟就能部署一个 OpenClaw 实例，自带 Web 设置向导、持久化存储、健康检查。</p><p><strong>ClawCloud Run</strong> 是持久容器，不休眠，适合需要长期在线的 Agent。</p><p>两个平台加起来，每月成本大约一杯咖啡 —— 不到 ¥36。</p><p>为什么选双平台？不是为了性能，是为了<strong>冗余</strong>。一个平台挂了，另一个还能继续工作。这在后面的故障案例里会看到有多重要。</p><hr><h2 id="运维踩坑实录" tabindex="-1">运维踩坑实录 <a class="header-anchor" href="#运维踩坑实录" aria-label="Permalink to &quot;运维踩坑实录&quot;">​</a></h2><h3 id="stale-lock-——-头号杀手" tabindex="-1">Stale Lock —— 头号杀手 <a class="header-anchor" href="#stale-lock-——-头号杀手" aria-label="Permalink to &quot;Stale Lock —— 头号杀手&quot;">​</a></h3><p>说回那次 6 小时宕机。根因是一个 <code>sessions.json.lock</code> 文件。Gateway 进程异常退出时没有清理这个 lock，下次启动就卡住了。</p><p>这不是一次性问题。我们前后遇到了三次：</p><table tabindex="0"><thead><tr><th>时间</th><th>故障</th><th>根因</th><th>影响</th></tr></thead><tbody><tr><td>03-09</td><td>Azure 404 循环刷屏</td><td>配置错误 + 无重试上限</td><td>刷屏数百条消息</td></tr><tr><td>03-11</td><td>6 小时宕机</td><td>Stale lock 文件</td><td>双 Agent 离线</td></tr><tr><td>03-11</td><td>WebSocket 断开</td><td>Stale lock 复发</td><td>消息丢失</td></tr></tbody></table><p>教训很简单：<strong>遇到 gateway 无响应，先查 lock 文件。</strong> 这个规则现在写进了我们的运维手册。</p><h3 id="平台自带的可靠性" tabindex="-1">平台自带的可靠性 <a class="header-anchor" href="#平台自带的可靠性" aria-label="Permalink to &quot;平台自带的可靠性&quot;">​</a></h3><p>Railway 自带健康检查。如果 <code>/healthz</code> 返回异常，它会自动重启容器。这不是我们写的代码，是平台能力。选对平台很重要。</p><h3 id="跨实例心跳监控" tabindex="-1">跨实例心跳监控 <a class="header-anchor" href="#跨实例心跳监控" aria-label="Permalink to &quot;跨实例心跳监控&quot;">​</a></h3><p>但平台只能保证单个容器活着，不能告诉你<strong>另一个 Agent 是不是也活着</strong>。</p><p>所以我们做了一个简单的跨实例心跳：每个 Agent 每 30 分钟往 GitHub 共享仓库写一个心跳文件。超过 60 分钟没更新，就发 Slack 告警。</p><p>加起来不到 30 行 shell 脚本。但如果 03-11 那天有这个机制，我们不会等 6 小时才发现问题。</p><hr><h2 id="多-agent-怎么不打架" tabindex="-1">多 Agent 怎么不打架？ <a class="header-anchor" href="#多-agent-怎么不打架" aria-label="Permalink to &quot;多 Agent 怎么不打架？&quot;">​</a></h2><p>两个 Agent 跑在不同平台上，怎么协作？</p><h3 id="协作协议" tabindex="-1">协作协议 <a class="header-anchor" href="#协作协议" aria-label="Permalink to &quot;协作协议&quot;">​</a></h3><p>我们设计了一套协作协议，解决几个核心问题：</p><p><strong>防循环</strong>：两个 Agent 在同一个 Slack 频道，看到消息都想回复，就会互相触发、无限循环。我们用了四层保护 —— 自我识别、回复深度控制、互斥响应、内容去重。</p><p><strong>任务分配</strong>：WLB 负责决策和规划，GSD 负责执行和落地。角色清晰，不重叠。</p><p><strong>状态同步</strong>：收到消息先加 👀 表情，处理完换 ✅。其他 Agent 看到 👀 就知道有人在处理了。</p><h3 id="jj-mailbox-——-异步持久化通信" tabindex="-1">jj-mailbox —— 异步持久化通信 <a class="header-anchor" href="#jj-mailbox-——-异步持久化通信" aria-label="Permalink to &quot;jj-mailbox —— 异步持久化通信&quot;">​</a></h3><p>Slack 是实时的，但如果 Agent 掉线了，消息就丢了。</p><p>我们设计了一个叫 jj-mailbox 的方案：本质就是一个 Git 仓库里的 JSON 文件系统。每个 Agent 有自己的 inbox 目录，消息写进去、git commit、git push。接收方 pull 之后读取。</p><p>好处是：<strong>Git 是免费的，自带版本历史，天然可追溯，不需要运维数据库。</strong> 对我们这种两个 Agent 的小团队，这是 sweet spot。</p><p>目前 jj-mailbox 的消息流和任务流已经验证通过，正在逐步投入生产使用。</p><h3 id="github-作为协作枢纽" tabindex="-1">GitHub 作为协作枢纽 <a class="header-anchor" href="#github-作为协作枢纽" aria-label="Permalink to &quot;GitHub 作为协作枢纽&quot;">​</a></h3><p>GitHub 在我们的方案里扮演了多个角色：代码仓库、心跳同步、jj-mailbox 消息通道、协作文档共享。一个免费的 GitHub repo，做了四件事。</p><hr><h2 id="三个核心-takeaway" tabindex="-1">三个核心 takeaway <a class="header-anchor" href="#三个核心-takeaway" aria-label="Permalink to &quot;三个核心 takeaway&quot;">​</a></h2><p><strong>第一，低成本 ≠ 低可靠。</strong> 两个平台加起来一杯咖啡的钱，但通过心跳监控和平台自带的恢复能力，可以做到合理的可用性。</p><p><strong>第二，协议 &gt; 默契。</strong> Agent 协作不能靠猜，要有明确的规则 —— 谁负责什么、怎么避免冲突、怎么同步状态。</p><p><strong>第三，失败是最好的老师。</strong> 我们的每一个运维规则，都是从真实故障里长出来的。</p><hr><h2 id="相关资源" tabindex="-1">相关资源 <a class="header-anchor" href="#相关资源" aria-label="Permalink to &quot;相关资源&quot;">​</a></h2><ul><li><strong>Railway 模板</strong>: <a href="https://github.com/ChaptersOfFloatingLife/clawdbot-railway-template" target="_blank" rel="noreferrer">clawdbot-railway-template</a></li><li><strong>GitHub 仓库</strong>: <a href="https://github.com/MiaoDX/claw-agents-shared" target="_blank" rel="noreferrer">MiaoDX/claw-agents-shared</a></li><li><strong>OpenClaw 文档</strong>: <a href="https://docs.openclaw.ai" target="_blank" rel="noreferrer">docs.openclaw.ai</a></li></ul><p>如果你也在玩多 Agent，欢迎交流。</p><hr><p><em>整理自 2026-03-15 OpenClaw Meetup 北京站分享</em><em>演讲者：缪东旭 (MiaoDX)</em></p>',54)])])}const b=a(l,[["render",n]]);export{g as __pageData,b as default};
